bg.disabled=var(--color-bg-disabled)[#F9FAFB]
text.default=var(--color-text-primary)
text.placeholder=var(--color-text-tertiary)
text.disabled=var(--color-text-disabled)[#D1D5DB]
border.default=var(--color-border-default)[#D1D5DB]
border.hover=var(--color-border-strong)
border.focus=var(--color-border-focus)[#3B82F6]
